-- Upsert Clock Tower junior novel vocabulary into public.word_bank.
-- Generated from src/data/juniorNovelWords.js.
ON CONFLICT (word, level) DO UPDATE SET
  pos = EXCLUDED.pos,
  meaning = EXCLUDED.meaning,
  ceec_level = COALESCE(public.word_bank.ceec_level, EXCLUDED.ceec_level),
  example = EXCLUDED.example,
  example_zh = EXCLUDED.example_zh,
  category = EXCLUDED.category,
  phonetic = COALESCE(NULLIF(public.word_bank.phonetic, ''), NULLIF(EXCLUDED.phonetic, ''), ''),
  forms = EXCLUDED.forms,
  collocations = EXCLUDED.collocations;
